 15тЖТ// eslint-disable-next-line @typescript-eslint/no-explicit-any -- drizzleAdapter accepts { [key: string]: any }
 16тЖТexport function createAuth(db: object, config: AuthConfig) {
 17тЖТ	const trustedOrigins = config.trustedOrigins ?? [];
 18тЖТ	if (!trustedOrigins.includes(config.appURL)) {
 19тЖТ		trustedOrigins.push(config.appURL);
 20тЖТ	}
 21тЖТ
 22тЖТ	return betterAuth({
 23тЖТ		baseURL: config.appURL,
 24тЖТ		secret: config.secret,
 25тЖТ		database: drizzleAdapter(db as Parameters<typeof drizzleAdapter>[0], {
 26тЖТ			provider: "pg",
 27тЖТ			schema,
 28тЖТ		}),
 29тЖТ		emailAndPassword: {
 30тЖТ			enabled: true,
 31тЖТ		},
 32тЖТ		socialProviders: config.socialProviders,
 33тЖТ		plugins: [
 34тЖТ			bearer(),
 35тЖТ			organization({
 36тЖТ				allowUserToCreateOrganization: true,
 37тЖТ				creatorRole: "owner",
 38тЖТ			}),
 39тЖТ		],
 40тЖТ		session: {
 41тЖТ			expiresIn: 60 * 60 * 24 * 365,
 42тЖТ		},
 43тЖТ		trustedOrigins,
 44тЖТ		databaseHooks: {
 45тЖТ			user: {
 46тЖТ				create: {
 47тЖТ					after: async (user, ctx) => {
 48тЖТ						try {
 49тЖТ							const adapter = ctx?.context?.adapter;
 50тЖТ							if (!adapter) return;
 51тЖТ
 52тЖТ							const slug = `${user.email.split("@")[0]}-${user.id.slice(0, 8)}`;
 53тЖТ							const org = await adapter.create({
 54тЖТ								model: "organization",
 55тЖТ								data: {
 56тЖТ									id: user.id,
 57тЖТ									name: `${user.name}'s Workspace`,
 58тЖТ									slug,
 59тЖТ									createdAt: new Date(),
 60тЖТ								},
 61тЖТ								forceAllowId: true,
 62тЖТ							});
 63тЖТ
 64тЖТ							if (org) {
 65тЖТ								await adapter.create({
 66тЖТ									model: "member",
 67тЖТ									data: {
 68тЖТ										organizationId: org.id,
 69тЖТ										userId: user.id,
 70тЖТ										role: "owner",
 71тЖТ										createdAt: new Date(),
 72тЖТ									},
 73тЖТ								});
 74тЖТ							}
 75тЖТ
 76тЖТ							if (config.slackWebhookUrl) {
 77тЖТ								let githubHandle: string | null = null;
 78тЖТ								const accounts = (await adapter.findMany({
 79тЖТ									model: "account",
 80тЖТ									where: [{ field: "userId", value: user.id }],
 81тЖТ								})) as Array<{ providerId: string; accountId: string }>;
 82тЖТ								const githubAccount = accounts.find(
 83тЖТ									(a) => a.providerId === "github",
 84тЖТ								);
 85тЖТ								if (githubAccount) {
 86тЖТ									githubHandle = await fetchGitHubHandle(
 87тЖТ										githubAccount.accountId,
 88тЖТ									);
 89тЖТ								}
 90тЖТ								await notifySignup(
 91тЖТ									config.slackWebhookUrl,
 92тЖТ									{ name: user.name, email: user.email },
 93тЖТ									githubHandle,
 94тЖТ								);
 95тЖТ							}
 96тЖТ						} catch (err) {
 97тЖТ							console.error(
 98тЖТ								"Failed to create default organization for user",
 99тЖТ								user.id,
100тЖТ								err,
101тЖТ							);
102тЖТ						}
103тЖТ					},
104тЖТ				},
105тЖТ			},
106тЖТ		},
107тЖТ	});
