  1тЖТimport { join } from "node:path";
  2тЖТimport { RPCHandler } from "@orpc/server/fetch";
  3тЖТimport { createAuth } from "./auth.js";
  4тЖТimport { db } from "./db.js";
  5тЖТimport { router } from "./router.js";
  6тЖТ
  7тЖТconst socialProviders: Record<
  8тЖТ	string,
  9тЖТ	{ clientId: string; clientSecret: string }
 10тЖТ> = {};
 11тЖТif (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
 12тЖТ	socialProviders.google = {
 13тЖТ		clientId: process.env.GOOGLE_CLIENT_ID,
 14тЖТ		clientSecret: process.env.GOOGLE_CLIENT_SECRET,
 15тЖТ	};
 16тЖТ}
 17тЖТif (process.env.GITHUB_CLIENT_ID && process.env.GITHUB_CLIENT_SECRET) {
 18тЖТ	socialProviders.github = {
 19тЖТ		clientId: process.env.GITHUB_CLIENT_ID,
 20тЖТ		clientSecret: process.env.GITHUB_CLIENT_SECRET,
 21тЖТ	};
 22тЖТ}
 23тЖТ
 24тЖТconst appURL = process.env.APP_URL ?? "http://localhost:4010";
 25тЖТconst trustedOrigins = process.env.TRUSTED_ORIGINS
 26тЖТ	? process.env.TRUSTED_ORIGINS.split(",").map((o) => o.trim())
 27тЖТ	: ["http://localhost:4011"];
 28тЖТ
 29тЖТconst auth = createAuth(db, {
 30тЖТ	appURL,
 31тЖТ	secret: process.env.BETTER_AUTH_SECRET,
 32тЖТ	socialProviders,
 33тЖТ	trustedOrigins,
 34тЖТ	slackWebhookUrl: process.env.SLACK_WEBHOOK_URL,
 35тЖТ});
 36тЖТ
 37тЖТconst rpcHandler = new RPCHandler(router);
 38тЖТ
 39тЖТconst ALLOWED_ORIGIN = process.env.ALLOWED_ORIGIN ?? "http://localhost:4011";
 40тЖТconst STATIC_DIR = join(
 41тЖТ	import.meta.dir,
 42тЖТ	"..",
 43тЖТ	process.env.STATIC_DIR ?? "public",
 44тЖТ);
 45тЖТ
 46тЖТfunction corsHeaders(origin: string | null): Record<string, string> {
 47тЖТ	if (origin !== ALLOWED_ORIGIN) return {};
 48тЖТ	return {
 49тЖТ		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
 50тЖТ		"Access-Control-Allow-Credentials": "true",
 51тЖТ		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 52тЖТ		"Access-Control-Allow-Headers": "Content-Type, Authorization",
 53тЖТ	};
 54тЖТ}
 55тЖТ
 56тЖТconst port = process.env.PORT ?? 4010;
 57тЖТ
 58тЖТconst server = Bun.serve({
 59тЖТ	port,
 60тЖТ	async fetch(request) {
 61тЖТ		const origin = request.headers.get("Origin");
 62тЖТ		const cors = corsHeaders(origin);
 63тЖТ
 64тЖТ		if (request.method === "OPTIONS") {
 65тЖТ			return new Response(null, { status: 204, headers: cors });
 66тЖТ		}
 67тЖТ
 68тЖТ		const url = new URL(request.url);
 69тЖТ
 70тЖТ		// Health check for Fly.io (must be GET-accessible)
 71тЖТ		if (url.pathname === "/health") {
 72тЖТ			return Response.json({ status: "ok", timestamp: Date.now() });
 73тЖТ		}
 74тЖТ
 75тЖТ		if (url.pathname === "/api/cli-token") {
 76тЖТ			const session = await auth.api.getSession({
 77тЖТ				headers: request.headers,
 78тЖТ			});
 79тЖТ			if (!session) {
 80тЖТ				return new Response(JSON.stringify({ error: "Not authenticated" }), {
 81тЖТ					status: 401,
 82тЖТ					headers: { ...cors, "Content-Type": "application/json" },
 83тЖТ				});
 84тЖТ			}
 85тЖТ			return new Response(JSON.stringify({ token: session.session.token }), {
 86тЖТ				status: 200,
 87тЖТ				headers: { ...cors, "Content-Type": "application/json" },
 88тЖТ			});
 89тЖТ		}
 90тЖТ
 91тЖТ		if (url.pathname.startsWith("/api/auth")) {
 92тЖТ			const response = await auth.handler(request);
 93тЖТ			for (const [key, value] of Object.entries(cors)) {
 94тЖТ				response.headers.set(key, value);
 95тЖТ			}
 96тЖТ			return response;
 97тЖТ		}
 98тЖТ
 99тЖТ		const { matched, response } = await rpcHandler.handle(request, {
100тЖТ			prefix: "/rpc",
101тЖТ			context: await getContext(request),
102тЖТ		});
103тЖТ
104тЖТ		if (matched) {
105тЖТ			// Log 500 errors for debugging
106тЖТ			if (response.status >= 500) {
107тЖТ				const body = await response.clone().text();
108тЖТ				console.error(`[RPC ${url.pathname}] ${response.status}:`, body);
109тЖТ			}
110тЖТ			for (const [key, value] of Object.entries(cors)) {
111тЖТ				response.headers.set(key, value);
112тЖТ			}
113тЖТ			return response;
114тЖТ		}
115тЖТ
116тЖТ		// Static file serving (production: frontend assets)
117тЖТ		const filePath = join(STATIC_DIR, url.pathname);
118тЖТ		const file = Bun.file(filePath);
119тЖТ		if (await file.exists()) {
120тЖТ			return new Response(file);
121тЖТ		}
122тЖТ
123тЖТ		// SPA fallback: serve index.html for non-API routes
124тЖТ		const indexFile = Bun.file(join(STATIC_DIR, "index.html"));
125тЖТ		if (await indexFile.exists()) {
126тЖТ			return new Response(indexFile);
127тЖТ		}
128тЖТ
129тЖТ		return new Response("Not found", { status: 404, headers: cors });
130тЖТ	},
131тЖТ});
132тЖТ
133тЖТasync function getContext(request: Request) {
134тЖТ	const session = await auth.api.getSession({
135тЖТ		headers: request.headers,
136тЖТ	});
137тЖТ	return {
138тЖТ		user: session?.user ?? null,
139тЖТ		session: session?.session ?? null,
140тЖТ	};
141тЖТ}
142тЖТ
143тЖТconsole.log(`API server listening on http://localhost:${server.port}`);
