 1тЖТimport { implement, ORPCError } from "@orpc/server";
 2тЖТimport { contract } from "@rudel/api-routes";
 3тЖТimport type { Session } from "./auth.js";
 4тЖТ
 5тЖТexport interface AppContext {
 6тЖТ	user: Session["user"] | null;
 7тЖТ	session: Session["session"] | null;
 8тЖТ}
 9тЖТ
10тЖТexport const os = implement(contract).$context<AppContext>();
11тЖТ
12тЖТexport const authMiddleware = os.middleware(async ({ context, next }) => {
13тЖТ	if (!context.user || !context.session) {
14тЖТ		throw new ORPCError("UNAUTHORIZED");
15тЖТ	}
16тЖТ	return next({
17тЖТ		context: {
18тЖТ			user: context.user,
19тЖТ			session: context.session,
20тЖТ		},
21тЖТ	});
22тЖТ});
23тЖТ
24тЖТexport const orgMiddleware = os.middleware(async ({ context, next }) => {
25тЖТ	if (!context.user || !context.session) {
26тЖТ		throw new ORPCError("UNAUTHORIZED");
27тЖТ	}
28тЖТ	const organizationId =
29тЖТ		(context.session as Record<string, unknown>).activeOrganizationId ??
30тЖТ		context.user.id;
31тЖТ	if (!organizationId || typeof organizationId !== "string") {
32тЖТ		throw new ORPCError("BAD_REQUEST", {
33тЖТ			message: "No active organization",
34тЖТ		});
35тЖТ	}
36тЖТ	return next({
37тЖТ		context: {
38тЖТ			user: context.user,
39тЖТ			session: context.session,
40тЖТ			organizationId,
41тЖТ		},
42тЖТ	});
43тЖТ});
