 23тЖТtype Page = "login" | "signup";
 24тЖТ
 25тЖТfunction getCliParams(): { cliCallback: string; state: string } | null {
 26тЖТ	const params = new URLSearchParams(window.location.search);
 27тЖТ	const cliCallback = params.get("cli_callback");
 28тЖТ	const state = params.get("state");
 29тЖТ	if (!cliCallback || !state) return null;
 30тЖТ	try {
 31тЖТ		const url = new URL(cliCallback);
 32тЖТ		if (url.hostname !== "127.0.0.1") return null;
 33тЖТ	} catch {
 34тЖТ		return null;
 35тЖТ	}
 36тЖТ	return { cliCallback, state };
 37тЖТ}
 38тЖТ
 39тЖТfunction getValidRedirect(): string | null {
 40тЖТ	const params = new URLSearchParams(window.location.search);
 41тЖТ	const redirect = params.get("redirect");
 42тЖТ	if (!redirect) return null;
 43тЖТ	if (!redirect.startsWith("/") || redirect.startsWith("//")) return null;
 44тЖТ	return redirect;
 45тЖТ}
 46тЖТ
 47тЖТfunction App() {
 48тЖТ	const { data: session, isPending } = authClient.useSession();
 49тЖТ	const [page, setPage] = useState<Page>("login");
 50тЖТ	const [cliRedirecting, setCliRedirecting] = useState(false);
 51тЖТ	const cliParams = getCliParams();
 52тЖТ	const { resolvedTheme } = useTheme();
 53тЖТ	const logoSrc =
 54тЖТ		resolvedTheme === "dark" ? "/logo-light.svg" : "/logo-dark.svg";
 55тЖТ
 56тЖТ	useEffect(() => {
 57тЖТ		if (!session || !cliParams || cliRedirecting) return;
 58тЖТ		setCliRedirecting(true);
 59тЖТ
 60тЖТ		fetch("/api/cli-token", { credentials: "include" })
 61тЖТ			.then((res) => res.json())
 62тЖТ			.then((data: { token: string }) => {
 63тЖТ				const redirectUrl = `${cliParams.cliCallback}?token=${encodeURIComponent(data.token)}&state=${encodeURIComponent(cliParams.state)}`;
 64тЖТ				window.location.href = redirectUrl;
 65тЖТ			});
 66тЖТ	}, [session, cliParams, cliRedirecting]);
 67тЖТ
 68тЖТ	if (isPending) {
 69тЖТ		return (
 70тЖТ			<div className="flex min-h-screen items-center justify-center">
 71тЖТ				<p className="text-muted-foreground">Loading...</p>
 72тЖТ			</div>
 73тЖТ		);
 74тЖТ	}
 75тЖТ
 76тЖТ	if (cliRedirecting) {
 77тЖТ		return (
 78тЖТ			<div className="flex min-h-screen items-center justify-center">
 79тЖТ				<p className="text-muted-foreground">Completing CLI login...</p>
 80тЖТ			</div>
 81тЖТ		);
 82тЖТ	}
 83тЖТ
 84тЖТ	if (!session) {
 85тЖТ		return (
 86тЖТ			<div className="flex min-h-screen flex-col items-center justify-center gap-6">
 87тЖТ				<img src={logoSrc} alt="Rudel" className="h-10 w-10" />
 88тЖТ				{page === "login" ? (
 89тЖТ					<LoginForm onSwitchToSignup={() => setPage("signup")} />
 90тЖТ				) : (
 91тЖТ					<SignupForm onSwitchToLogin={() => setPage("login")} />
 92тЖТ				)}
 93тЖТ			</div>
 94тЖТ		);
 95тЖТ	}
 96тЖТ
 97тЖТ	return (
 98тЖТ		<Routes>
 99тЖТ			<Route
100тЖТ				path="/"
101тЖТ				element={<Navigate to={getValidRedirect() || "/dashboard"} replace />}
102тЖТ			/>
103тЖТ			<Route
104тЖТ				path="/invitation/:invitationId"
105тЖТ				element={<AcceptInvitationPage />}
106тЖТ			/>
107тЖТ			<Route path="/dashboard" element={<DashboardLayout />}>
108тЖТ				<Route index element={<OverviewPage />} />
109тЖТ				<Route path="developers" element={<DevelopersListPage />} />
110тЖТ				<Route path="developers/:userId" element={<DeveloperDetailPage />} />
111тЖТ				<Route path="projects" element={<ProjectsListPage />} />
112тЖТ				<Route path="projects/:projectPath" element={<ProjectDetailPage />} />
113тЖТ				<Route path="sessions" element={<SessionsListPage />} />
114тЖТ				<Route path="sessions/:sessionId" element={<SessionDetailPage />} />
115тЖТ				<Route path="roi" element={<ROIPage />} />
116тЖТ				<Route path="errors" element={<ErrorsPage />} />
117тЖТ				<Route path="learnings" element={<LearningsPage />} />
118тЖТ				<Route path="profile" element={<ProfilePage />} />
119тЖТ				<Route path="organization" element={<OrganizationPage />} />
120тЖТ				<Route path="organization/new" element={<CreateOrgPage />} />
121тЖТ			</Route>
122тЖТ			<Route path="*" element={<Navigate to="/dashboard" replace />} />
123тЖТ		</Routes>
124тЖТ	);
125тЖТ}
