38тЖТ				logo: organization.logo,
39тЖТ			})
40тЖТ			.from(member)
41тЖТ			.innerJoin(organization, eq(member.organizationId, organization.id))
42тЖТ			.where(eq(member.userId, context.user.id));
43тЖТ
44тЖТ		return memberships.map((m) => ({
45тЖТ			id: m.id,
46тЖТ			name: m.name,
47тЖТ			slug: m.slug,
