52тЖТconst ingestSessionHandler = os.ingestSession
53тЖТ	.use(authMiddleware)
54тЖТ	.handler(async ({ input, context }) => {
55тЖТ		const orgId =
56тЖТ			input.organizationId ??
57тЖТ			((context.session as Record<string, unknown>).activeOrganizationId as
58тЖТ				| string
59тЖТ				| null) ??
60тЖТ			context.user.id;
