64тЖТ				.select({ id: member.id })
65тЖТ				.from(member)
66тЖТ				.where(
67тЖТ					and(
68тЖТ						eq(member.organizationId, input.organizationId),
69тЖТ						eq(member.userId, context.user.id),
70тЖТ					),
71тЖТ				)
72тЖТ				.limit(1);
73тЖТ
74тЖТ			if (membership.length === 0) {
75тЖТ				throw new ORPCError("FORBIDDEN", {
76тЖТ					message: "Not a member of the specified organization",
77тЖТ				});
78тЖТ			}
79тЖТ		}
80тЖТ
81тЖТ		await ingestSession(getClickhouse(), input, {
82тЖТ			userId: context.user.id,
83тЖТ			organizationId: orgId,
84тЖТ		});
85тЖТ
86тЖТ		return {
87тЖТ			success: true as const,
88тЖТ			sessionId: input.sessionId,
89тЖТ		};
90тЖТ	});
