148тЖТconst testId = `api_test_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
149тЖТ
150тЖТconst baseExecutor = createClickHouseExecutor({
151тЖТ	url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
152тЖТ	username:
153тЖТ		process.env.CLICKHOUSE_USERNAME || process.env.CLICKHOUSE_USER || "default",
154тЖТ	password: process.env.CLICKHOUSE_PASSWORD || "",
155тЖТ	database: "default",
156тЖТ});
157тЖТ
158тЖТ// ClickHouse Cloud's @clickhouse/client insert() silently drops data.
159тЖТ// Wrap the executor to use execute() with FORMAT JSONEachRow instead.
160тЖТ// async_insert=0 forces synchronous insert so data is immediately queryable.
161тЖТconst executor: typeof baseExecutor = {
162тЖТ	...baseExecutor,
163тЖТ	async insert(params) {
164тЖТ		const rows = params.values.map((r) => JSON.stringify(r)).join("\n");
165тЖТ		await baseExecutor.execute(
166тЖТ			`INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`,
167тЖТ		);
168тЖТ	},
169тЖТ};
170тЖТ
171тЖТafterAll(() => {
172тЖТ	// Fire-and-forget: ClickHouse Cloud DELETE mutations are slow
173тЖТ	executor
174тЖТ		.execute(`DELETE FROM rudel.claude_sessions WHERE session_id = '${testId}'`)
175тЖТ		.catch(() => {});
176тЖТ});
