178тЖТasync function waitForRow(
179тЖТ	sessionId: string,
180тЖТ	timeoutMs = 30000,
181тЖТ	intervalMs = 2000,
182тЖТ): Promise<
183тЖТ	Array<{
184тЖТ		session_id: string;
185тЖТ		project_path: string;
186тЖТ		repository: string;
187тЖТ		tag: string;
188тЖТ		user_id: string;
189тЖТ		organization_id: string;
190тЖТ	}>
191тЖТ> {
192тЖТ	const start = Date.now();
