14тЖТ	sessionDate: string;
15тЖТ	lastInteractionDate: string;
16тЖТ} | null {
17тЖТ	let min: string | null = null;
18тЖТ	let max: string | null = null;
19тЖТ
20тЖТ	for (const line of content.split("\n")) {
21тЖТ		if (!line) continue;
