27тЖТ		}
28тЖТ		if (
29тЖТ			(parsed.type === "user" || parsed.type === "assistant") &&
30тЖТ			parsed.timestamp
31тЖТ		) {
32тЖТ			const ts = parsed.timestamp;
33тЖТ			if (!min || ts < min) min = ts;
34тЖТ			if (!max || ts > max) max = ts;
35тЖТ		}
36тЖТ	}
37тЖТ
38тЖТ	if (!min || !max) return null;
39тЖТ
40тЖТ	return { sessionDate: min, lastInteractionDate: max };
41тЖТ}
